const [atual, anterior] = $input.all().map(i => i.json);

function n(v) {
  return Number(v ?? 0);
}

function variacao(a, b) {
  if (!isFinite(a) || !isFinite(b) || b === 0) return null;
  return ((a - b) / b) * 100;
}

function variacaoPP(a, b) {
  if (!isFinite(a) || !isFinite(b)) return null;
  return a - b;
}

function icone(v, menorMelhor = false) {
  if (v === null) return "➖";
  if (Math.abs(v) < 0.01) return "➖";

  if (menorMelhor) {
    return v < 0 ? "⬆️" : "⬇️";
  }

  return v > 0 ? "⬆️" : "⬇️";
}

function preparar(d){

    d.investimento = n(d.investimento);
    d.impressoes = n(d.impressoes);
    d.cliques = n(d.cliques);
    d.visitas_pagina = n(d.visitas_pagina);
    d.checkouts = n(d.checkouts);

    d.vendas_produto_principal = n(d.vendas_produto_principal);
    d.vendas_orderbump = n(d.vendas_orderbump);

    d.faturamento = n(d.faturamento);

    d.ctr = n(d.ctr);
    d.connect_rate = n(d.connect_rate);
    d.conversao_pagina = n(d.conversao_pagina);
    d.conversao_checkout = n(d.conversao_checkout);

    d.roas = n(d.roas);

    d.custo_principal =
        d.vendas_produto_principal > 0
            ? d.investimento / d.vendas_produto_principal
            : null;

    d.conversao_orderbump =
        d.vendas_produto_principal > 0
            ? d.vendas_orderbump / d.vendas_produto_principal * 100
            : null;

    return d;
}

const a = preparar(atual);
const b = preparar(anterior);

const camposPct = [
    "cliques",
    "visitas_pagina",
    "vendas_produto_principal",
    "vendas_orderbump",
    "conversao_orderbump",
    "investimento",
    "faturamento",
    "roas",
    "custo_principal"
];

const camposPP = [
    "ctr",
    "connect_rate",
    "conversao_pagina",
    "conversao_checkout"
];

const comparativo = {};

for(const c of camposPct){

    const v = variacao(a[c], b[c]);

    comparativo[c] = {
        variacao:v,
        icone:icone(v,c==="custo_principal")
    };

}

for(const c of camposPP){

    const v = variacaoPP(a[c],b[c]);

    comparativo[c]={
        variacao_pp:v,
        icone:icone(v,false)
    };

}

return [{
    json:{
        atual:a,
        anterior:b,
        comparativo
    }
}];

